def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 10):
            if ratio < 0.05 * j:
                score += (10 - j) * np.exp(-ratio * j) + np.cos(ratio * np.pi * j)
            elif 0.05 * j <= ratio < 0.3:
                score += (j ** 3) * np.sin(ratio * np.pi * j) / (j + 1)
            elif 0.3 <= ratio < 0.7:
                score += np.log1p(ratio * j) * (j / 3) + np.tanh(ratio * j)
            else:
                score += np.sqrt(ratio * j) * (j / 2) - np.exp(-j * ratio)
        if capacity - item < 0.1 * capacity:
            score *= 2.5
            for k in range(1, 5):
                if (capacity - item) / capacity < 0.02 * k:
                    score += k * np.log1p(item / (capacity + 1e-6))
        elif capacity - item < 0.3 * capacity:
            score *= 1.5
            for m in range(1, 3):
                if (capacity - item) / capacity > 0.1 * m:
                    score += m * np.sqrt(item / capacity) * np.sin(m * np.pi * ratio)
        else:
            for n in range(1, 6):
                if (capacity - item) / capacity > 0.3 * n / 5:
                    score += np.tanh(n * ratio) * np.log1p(n + item)
                else:
                    score -= np.exp(-n * ratio) * (n / 2)
        if item > 0.9 * capacity:
            score += np.tanh(item / capacity) * 7
            if ratio > 0.95:
                score += np.log1p(item * capacity) * 0.5
        elif item < 0.2 * capacity:
            score -= np.exp(-ratio * 10) * 3
        if score < 0:
            score = abs(score) * 0.7 + 1
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1
    else:
        max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority * 4
    return priorities
